#!/usr/bin/env python3
"""encode-knot.py — HF → KNOT encoder for standard transformer architectures.

Supports (Tier-1 inference candidates):
  HuggingFaceTB/SmolLM2-360M-Instruct     → arch="llama"   (LlamaForCausalLM)
  google/gemma-3-1b-it                     → arch="gemma3"  (Gemma3ForCausalLM)
  deepseek-ai/DeepSeek-R1-Distill-Qwen-1.5B → arch="qwen2" (Qwen2ForCausalLM)
  stabilityai/stablelm-zephyr-3b           → arch="qwen2"   (StableLmForCausalLM)
  google/gemma-3-4b-it                     → arch="gemma3"  (Gemma3ForCausalLM)
  google/gemma-4-e4b-it                    → arch="gemma4"  (Gemma4ForCausalLM)
  Qwen/Qwen2.5-Coder-7B-Instruct           → arch="qwen2"   (Qwen2ForCausalLM)
  Qwen/Qwen3-30B-A3B                       → arch="qwen3moe" (Qwen3MoeForCausalLM, partial)
  mistralai/Codestral-22B-v0.1             → arch="llama"   (MistralForCausalLM)

Writes KNOT format files compatible with NativeLlamaPipeline in model.rs.
Tensor keys match exactly what resolve_all() in model.rs expects.

Quantization: large projection matrices (≥ 65536 elements) are Q8_0-quantized
(32-element blocks: 1 f32 absmax + 32 i8 values). Norms, biases, embeddings,
and lm_head are kept F32.

Usage:
    python3 encode-knot.py \\
        --model HuggingFaceTB/SmolLM2-360M-Instruct \\
        --output rknots/smollm2-360m.knot \\
        --hf-token $HF_TOKEN

    python3 encode-knot.py \\
        --model google/gemma-3-1b-it \\
        --output rknots/gemma3-1b.knot \\
        --max-layers 4   # fast iteration

    python3 encode-knot.py \\
        --model Qwen/Qwen2.5-Coder-7B-Instruct \\
        --output rknots/qwen-edit.knot
"""
from __future__ import annotations

import argparse
import json
import os
import re
import shutil
import struct
import sys
import tempfile
from pathlib import Path
from typing import Any

import numpy as np
import ml_dtypes  # registers bfloat16 with numpy so safetensors can decode bf16 tensors

# ─────────────────────────────────────────────────────────────────────────────
# Q8_0 quantization (compatible with fat-station dequant kernel)
# Block: 2-byte fp16 scale + 32 signed bytes = 34 bytes per 32 elements.
# ─────────────────────────────────────────────────────────────────────────────

Q8_0_BLOCK = 32

# Tensors at/above this element count are Q8-encoded by streaming row-blocks
# straight from the safetensors slice (peak RAM ~ one chunk) instead of loading
# + dequantizing the whole tensor (which peaks >2x the f32 size and OOMs). The
# E4B `embed_tokens_per_layer` PLE table (~5.5GB bf16) is the motivating case.
STREAM_Q8_THRESHOLD = int(os.getenv("KNOT_STREAM_TENSOR_NUMEL", str(800_000_000)))

def _to_f32(raw: "np.ndarray") -> "np.ndarray":
    """Convert any safetensors numpy array to float32 (handles bfloat16)."""
    if "bfloat16" in str(raw.dtype):
        u16 = np.frombuffer(raw.tobytes(), dtype=np.uint16)
        return (u16.astype(np.uint32) << 16).view(np.float32).reshape(raw.shape)
    return raw.astype(np.float32)

def _q8_0_encode(arr: np.ndarray) -> bytes:
    """Quantize to GGUF-standard Q8_0: per 32-elem block = fp16 scale d (2 bytes)
    + 32 int8. d = amax/127; qs[j] = round(x[j]/d); dequant x = d*qs.

    MUST match the runtime dequantize_q8_0_row (math.rs:153): 34-byte blocks,
    little-endian fp16 scale, then 32 i8. The previous layout (4-byte f32 absmax
    + 32 i8 = 36 bytes) mismatched both the stride (34 vs 36) and the scale type
    (fp16 vs f32), so every encoder-produced Q8_0 tensor dequantized to garbage
    -> all-NaN forward (qwen3-4b / llama-3.2-3b / deepseek-r1-1.5b L0 NaN)."""
    arr = arr.astype(np.float32).flatten()
    pad = (-len(arr)) % Q8_0_BLOCK
    if pad:
        arr = np.pad(arr, (0, pad))
    # Vectorized (numpy) -- a per-block Python loop is the encode bottleneck for
    # 7B models (minutes/tensor). Reshape to blocks and quantize in one shot.
    blocks = arr.reshape(-1, Q8_0_BLOCK)                 # (n_blocks, 32)
    amax = np.abs(blocks).max(axis=1)                    # (n_blocks,)
    d = amax / 127.0
    with np.errstate(divide="ignore", invalid="ignore"):
        inv = np.where(d > 0.0, 1.0 / d, 0.0)           # safe 0-block handling
    q = np.clip(np.round(blocks * inv[:, None]), -127, 127).astype(np.int8)
    d16 = d.astype(np.float16)
    out = np.empty((blocks.shape[0], 2 + Q8_0_BLOCK), dtype=np.uint8)
    out[:, :2] = d16.view(np.uint8).reshape(-1, 2)       # 2-byte LE fp16 scale
    out[:, 2:] = q.view(np.uint8)                        # 32 signed bytes
    return out.tobytes()


# ─────────────────────────────────────────────────────────────────────────────
# KNOT format writer (mirrors KnotWriter in encode-ssm-models.py)
# ─────────────────────────────────────────────────────────────────────────────

class KnotWriter:
    """Streams encoded tensors to a temp file to avoid accumulating the full
    payload (~40 GB for 70B Q4K) in memory. Peak RAM is one shard at a time
    rather than the entire encoded output.

    For very large image models, set KNOT_STREAM_DIRECT=1 and pass output_path.
    That reserves a fixed metadata field in the KNOT header, streams tensor
    payload bytes directly into the final file, then seeks back to write JSON
    metadata padded with trailing whitespace. KNOT readers already derive the
    payload offset from metadata_len, and JSON parsers accept the trailing
    whitespace, so this preserves the on-disk format while avoiding a second
    full-size payload copy during encode.
    """

    def __init__(self, name: str, arch: str, config: dict[str, Any],
                 components: dict[str, Any] | None = None,
                 output_path: Path | None = None):
        self._name = name
        self._arch = arch
        self._config = config
        self._components = components
        self._tensor_meta: list[tuple[str, str, int, int, tuple[int, ...]]] = []
        self._offset = 0
        self._tmp = None
        self._direct_file = None
        self._direct_path = output_path
        self._direct_meta_reserve = 0
        self._direct = os.getenv("KNOT_STREAM_DIRECT") == "1"
        if self._direct:
            if output_path is None:
                raise ValueError("KNOT_STREAM_DIRECT requires KnotWriter(output_path=...)")
            self._direct_meta_reserve = int(
                os.getenv("KNOT_HEADER_RESERVE_BYTES", str(2 * 1024 * 1024))
            )
            if self._direct_meta_reserve <= 0:
                raise ValueError("KNOT_HEADER_RESERVE_BYTES must be positive")
            output_path.parent.mkdir(parents=True, exist_ok=True)
            self._direct_file = open(output_path, "wb+")
            self._write_placeholder_header(self._direct_file, self._direct_meta_reserve)
        else:
            self._tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".knot.payload")

    @staticmethod
    def _write_placeholder_header(handle, metadata_len: int) -> None:
        handle.write(b"KNOT")
        handle.write(struct.pack("<H", 1))
        handle.write(struct.pack("<I", metadata_len))
        handle.write(b" " * metadata_len)
        pad = (-(10 + metadata_len)) % 4
        handle.write(b"\x00" * pad)
        handle.write(b"\x20")

    def _metadata_bytes(self) -> bytes:
        tensor_meta: dict[str, Any] = {}
        for canon, qtype, offset, length, shape in self._tensor_meta:
            key = canon.replace(".", "_") + ".bin"
            tensor_meta[key] = {
                "offset": offset,
                "length": length,
                "type": qtype,
                "shape": list(shape),
            }

        meta = {"name": self._name, "arch": self._arch,
                "config": self._config, "tensors": tensor_meta}
        if self._components is not None:
            meta["components"] = self._components
        return json.dumps(meta).encode()

    def _stream(self, canon: str, qtype: str, raw: bytes, shape: tuple[int, ...]) -> None:
        if self._direct:
            assert self._direct_file is not None
            self._direct_file.write(raw)
        else:
            assert self._tmp is not None
            self._tmp.write(raw)
        self._tensor_meta.append((canon, qtype, self._offset, len(raw), shape))
        self._offset += len(raw)

    def add_f32(self, name: str, arr: np.ndarray) -> None:
        self._stream(
            name,
            "F32",
            arr.astype(np.float32).flatten().tobytes(),
            tuple(int(dim) for dim in arr.shape),
        )

    def add_q8(self, name: str, arr: np.ndarray) -> None:
        self._stream(
            name,
            "Q8_0",
            _q8_0_encode(arr),
            tuple(int(dim) for dim in arr.shape),
        )

    def add_q8_streamed(self, name: str, sl, shape: tuple[int, ...],
                        chunk_rows: int = 8192) -> None:
        """Stream-encode a large 2-D tensor to Q8_0 directly from a safetensors
        slice handle, a row-block at a time, so peak RAM is ~one chunk instead of
        the whole (de)quantized tensor. Q8_0 blocks are independent (per-block
        scale), so encoding in 32-aligned segments is byte-identical to encoding
        the whole flattened tensor; a carry buffer preserves block alignment
        across chunk boundaries. Motivating case: E4B embed_tokens_per_layer."""
        handle = self._direct_file if self._direct else self._tmp
        assert handle is not None
        start_off = self._offset
        total = 0
        rows = int(shape[0])
        carry = np.empty(0, dtype=np.float32)
        for i in range(0, rows, chunk_rows):
            sub = _to_f32(sl[i:i + chunk_rows]).reshape(-1)
            buf = np.concatenate([carry, sub]) if carry.size else sub
            n_full = (buf.size // Q8_0_BLOCK) * Q8_0_BLOCK
            if n_full:
                raw = _q8_0_encode(buf[:n_full])   # exact 32-multiple -> no padding
                handle.write(raw)
                total += len(raw)
            carry = buf[n_full:].copy()
        if carry.size:                             # final partial block -> padded
            raw = _q8_0_encode(carry)
            handle.write(raw)
            total += len(raw)
        self._tensor_meta.append(
            (name, "Q8_0", start_off, total, tuple(int(dim) for dim in shape)))
        self._offset += total

    def add_auto(self, name: str, arr: np.ndarray, large_threshold: int = 65536) -> None:
        if os.getenv("KNOT_FORCE_F32") == "1":
            self.add_f32(name, arr)
            return
        if arr.size >= large_threshold:
            self.add_q8(name, arr)
        else:
            self.add_f32(name, arr)

    def write(self, path: Path) -> None:
        meta_bytes = self._metadata_bytes()

        if self._direct:
            assert self._direct_file is not None
            if path != self._direct_path:
                raise ValueError("direct KNOT writer output path changed before write()")
            if len(meta_bytes) > self._direct_meta_reserve:
                self._direct_file.close()
                raise RuntimeError(
                    "KNOT metadata exceeded KNOT_HEADER_RESERVE_BYTES: "
                    f"{len(meta_bytes)} > {self._direct_meta_reserve}"
                )
            self._direct_file.flush()
            self._direct_file.seek(0)
            self._direct_file.write(b"KNOT")
            self._direct_file.write(struct.pack("<H", 1))
            self._direct_file.write(struct.pack("<I", self._direct_meta_reserve))
            self._direct_file.write(meta_bytes)
            self._direct_file.write(b" " * (self._direct_meta_reserve - len(meta_bytes)))
            self._direct_file.close()

            size_mb = path.stat().st_size / 1024 / 1024
            print(
                f"[knot] wrote {path} ({size_mb:.1f} MB, "
                f"{len(self._tensor_meta)} tensors, direct-stream)",
                file=sys.stderr,
            )
            return

        magic = b"KNOT"
        version = struct.pack("<H", 1)
        meta_len = struct.pack("<I", len(meta_bytes))
        header = magic + version + meta_len + meta_bytes
        pad = (-len(header)) % 4
        header += b"\x00" * pad
        header += b"\x20"  # codec marker (fp32 default; per-tensor types in metadata)

        path.parent.mkdir(parents=True, exist_ok=True)
        assert self._tmp is not None
        self._tmp.flush()
        with open(path, "wb") as f:
            f.write(header)
            self._tmp.seek(0)
            shutil.copyfileobj(self._tmp, f, length=64 * 1024 * 1024)  # 64 MiB chunks

        self._tmp.close()
        os.unlink(self._tmp.name)

        size_mb = path.stat().st_size / 1024 / 1024
        print(f"[knot] wrote {path} ({size_mb:.1f} MB, {len(self._tensor_meta)} tensors)",
              file=sys.stderr)


# ─────────────────────────────────────────────────────────────────────────────
# Tensor name patterns
#
# All standard transformer archs (llama, qwen2, gemma3, gemma4, stablelm)
# share the same HF state_dict naming, so one pattern table covers them.
# Gemma3/4 carry extra per-head norms and double-norm layers; those are
# optional in the KNOT (try_resolve_tensor in model.rs returns None when absent).
# ─────────────────────────────────────────────────────────────────────────────

# Layer patterns: (compiled_regex, canonical_template)
# {n} is replaced with the matched layer index.
_LAYER_PATTERNS: list[tuple[re.Pattern, str]] = [
    # ── Pre-attention norm ──────────────────────────────────────────────────
    (re.compile(r"^model\.layers\.(\d+)\.input_layernorm\.weight$"),
     "blk.{n}.attn_norm.weight"),

    # ── Attention projections ───────────────────────────────────────────────
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.q_proj\.weight$"),
     "blk.{n}.attn_q.weight"),
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.k_proj\.weight$"),
     "blk.{n}.attn_k.weight"),
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.v_proj\.weight$"),
     "blk.{n}.attn_v.weight"),
    # NOTE: model.rs uses "attn_output_weight" (not "attn_o_weight") — must match.
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.o_proj\.weight$"),
     "blk.{n}.attn_output.weight"),

    # ── QKV biases (Qwen2 / some models) ────────────────────────────────────
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.q_proj\.bias$"),
     "blk.{n}.attn_q.bias"),
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.k_proj\.bias$"),
     "blk.{n}.attn_k.bias"),
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.v_proj\.bias$"),
     "blk.{n}.attn_v.bias"),

    # ── Per-head norms (Gemma3 / Gemma4) ────────────────────────────────────
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.q_norm\.weight$"),
     "blk.{n}.attn_q_norm.weight"),
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.k_norm\.weight$"),
     "blk.{n}.attn_k_norm.weight"),

    # ── Post-attention + post-FFN norms (Gemma3 / Gemma4 double-norm) ───────
    (re.compile(r"^model\.layers\.(\d+)\.pre_feedforward_layernorm\.weight$"),
     "blk.{n}.post_attention_norm.weight"),
    (re.compile(r"^model\.layers\.(\d+)\.post_feedforward_layernorm\.weight$"),
     "blk.{n}.post_ffw_norm.weight"),

    # ── FFN pre-norm ─────────────────────────────────────────────────────────
    (re.compile(r"^model\.layers\.(\d+)\.post_attention_layernorm\.weight$"),
     "blk.{n}.ffn_norm.weight"),

    # ── Phi-3 / GLM-4 style fused QKV + fused gate_up ───────────────────────
    # HF Phi-3: qkv_proj packs [Q|K|V] rows; gate_up_proj packs [gate|up] rows.
    # model_phi3.rs expects blk_N_attn_qkv_weight + blk_N_ffn_up_weight.
    (re.compile(r"^model\.layers\.(\d+)\.self_attn\.qkv_proj\.weight$"),
     "blk.{n}.attn_qkv.weight"),
    (re.compile(r"^model\.layers\.(\d+)\.mlp\.gate_up_proj\.weight$"),
     "blk.{n}.ffn_up.weight"),

    # ── FFN projections (SwiGLU: gate + up → down) ───────────────────────────
    (re.compile(r"^model\.layers\.(\d+)\.mlp\.gate_proj\.weight$"),
     "blk.{n}.ffn_gate.weight"),
    (re.compile(r"^model\.layers\.(\d+)\.mlp\.up_proj\.weight$"),
     "blk.{n}.ffn_up.weight"),
    (re.compile(r"^model\.layers\.(\d+)\.mlp\.down_proj\.weight$"),
     "blk.{n}.ffn_down.weight"),

    # ── Layer output scale (Gemma4) ──────────────────────────────────────────
    (re.compile(r"^model\.layers\.(\d+)\.layer_output_scale$"),
     "blk.{n}.layer_output_scale.weight"),
    (re.compile(r"^model\.layers\.(\d+)\.layer_output_scale\.weight$"),
     "blk.{n}.layer_output_scale.weight"),
]

