_FLUX_NON_WEIGHT_COMPONENTS = ("tokenizer", "tokenizer_2", "scheduler", "feature_extractor")
_FLUX_COMPONENT_POLICY = "flux-with-vae-text-encoders"
_FLUX_AUX_CANON_PREFIXES = {
    "vae": "flux.vae",
    "text_encoder": "flux.clip",
    "text_encoder_2": "flux.t5",
}
_FLUX_REQUIRED_TENSOR_PREFIXES = {
    "transformer": ("flux_img_in_", "flux_dbl_", "flux_sgl_"),
    "vae": ("flux_vae_",),
    "text_encoder": ("flux_clip_",),
    "text_encoder_2": ("flux_t5_",),
}

_BASE_SNAPSHOT_IGNORE_PATTERNS = [
    "*.msgpack", "*.h5", "flax_model*", "tf_model*", "rust_model*", "*.bin",
]


def _component_metadata_for_arch(arch: str) -> dict[str, Any] | None:
    if arch != "flux":
        return None
    return {
        "included": list(_FLUX_WEIGHT_COMPONENTS),
        "skipped": list(_FLUX_NON_WEIGHT_COMPONENTS),
        "policy": _FLUX_COMPONENT_POLICY,
    }


def _snapshot_ignore_patterns_for_arch(arch: str) -> list[str]:
    patterns = list(_BASE_SNAPSHOT_IGNORE_PATTERNS)
    if arch == "flux":
        patterns.extend(f"{component}/*" for component in _FLUX_NON_WEIGHT_COMPONENTS)
    return patterns


def _snapshot_allow_patterns_for_arch(arch: str) -> list[str] | None:
    if arch == "flux":
        # FLUX repos commonly carry legacy root-level BFL safetensors
        # (`flux1-*.safetensors`, `ae.safetensors`) alongside the diffusers
        # component directories. The native KNOT path needs the component
        # directories because they carry transformer, VAE, CLIP, and T5 with
        # shape-aware names. Allow-listing component directories avoids downloading
        # duplicate root payload.
        return [f"{component}/*" for component in _FLUX_WEIGHT_COMPONENTS]

    # Standard text-model KNOT builds need weights + config/tokenizer sidecars,
    # not README/license files or auxiliary cards. This also keeps very large
    # repos such as Codestral from spawning unnecessary concurrent downloads.
    return [
        "*.json",
        "*.safetensors",
        "*.safetensors.index.json",
        "*.model",
        "*.txt",
        "params.json",
        "tokenizer*",
    ]


def _local_model_dir(model_id: str) -> Path | None:
    candidate = Path(model_id).expanduser()
    if candidate.exists():
        return candidate
    return None


def _load_local_config_namespace(model_id: str):
    local_dir = _local_model_dir(model_id)
    if local_dir is None:
        return None
    from types import SimpleNamespace
    for cfg_path in (local_dir / "config.json", local_dir / "transformer" / "config.json"):
        if cfg_path.exists():
            with open(cfg_path) as f:
                return SimpleNamespace(**json.load(f))
    return None


def _resolve_model_dir(model_id: str, *, arch: str, snapshot_download,
                       revision: str, hf_token: str | None) -> Path:
    local_dir = _local_model_dir(model_id)
    if local_dir is not None:
        if not local_dir.is_dir():
            print(f"ERROR: local model path is not a directory: {local_dir}", file=sys.stderr)
            sys.exit(1)
        return local_dir
    return Path(snapshot_download(
        model_id, revision=revision, token=hf_token,
        allow_patterns=_snapshot_allow_patterns_for_arch(arch),
        ignore_patterns=_snapshot_ignore_patterns_for_arch(arch),
    ))


def _shard_files_for_arch(local_dir: Path, arch: str, glob_module) -> list[str]:
    if arch == "flux":
        component_shards: list[str] = []
        for component in _FLUX_WEIGHT_COMPONENTS:
            component_shards.extend(sorted(glob_module.glob(str(local_dir / component / "*.safetensors"))))
        if component_shards:
            return sorted(dict.fromkeys(component_shards))
        return sorted(glob_module.glob(str(local_dir / "*.safetensors")))

    shard_files = sorted(glob_module.glob(str(local_dir / "*.safetensors")))
    if not shard_files:
        shard_files = sorted(glob_module.glob(str(local_dir / "transformer" / "*.safetensors")))
    return shard_files


def _flux_component_for_shard(local_dir: Path, shard_path: str) -> str | None:
    try:
        # Hugging Face snapshots are usually symlink forests into cache blobs.
        # Do not resolve symlinks here: resolving moves the shard path outside
        # the snapshot tree and loses the component directory (`vae/`,
        # `text_encoder/`, `text_encoder_2/`) we need for FLUX namespacing.
        rel_parts = Path(shard_path).absolute().relative_to(local_dir.absolute()).parts
    except ValueError:
        return None
    if rel_parts and rel_parts[0] in _FLUX_WEIGHT_COMPONENTS:
        return rel_parts[0]
    return None


def _maybe_delete_shard_after_encode(local_dir: Path, shard_path: str) -> None:
    if os.getenv("KNOT_DELETE_SHARDS_AFTER_ENCODE") != "1":
        return
    shard = Path(shard_path)
    try:
        shard.absolute().relative_to(local_dir.absolute())
    except ValueError:
        return

    candidates: list[Path] = [shard]
    try:
        resolved = shard.resolve(strict=True)
        if resolved != shard:
            candidates.append(resolved)
    except OSError:
        pass

    for candidate in candidates:
        try:
            if candidate.exists() or candidate.is_symlink():
                candidate.unlink()
                print(f"[knot] reclaimed encoded shard {candidate}", file=sys.stderr)
        except OSError as exc:
            print(f"[knot] warning: could not reclaim {candidate}: {exc}", file=sys.stderr)


def _read_knot_metadata(path: Path) -> dict[str, Any]:
    with open(path, "rb") as f:
        magic = f.read(4)
        if magic != b"KNOT":
            raise ValueError(f"{path} is not a KNOT file")
        f.read(2)
        meta_len = struct.unpack("<I", f.read(4))[0]
        return json.loads(f.read(meta_len).decode())


def _validate_flux_knot_metadata(metadata: dict[str, Any]) -> list[str]:
    config = metadata.get("config")
    config_arch = config.get("arch") if isinstance(config, dict) else None
    arch = metadata.get("arch") or config_arch
    if arch != "flux":
        return []

    problems: list[str] = []
    components = metadata.get("components")
    if not isinstance(components, dict):
        problems.append("missing top-level components metadata")
    else:
        included = set(components.get("included") or [])
        skipped = set(components.get("skipped") or [])
        missing_included = [c for c in _FLUX_WEIGHT_COMPONENTS if c not in included]
        missing_skipped = [c for c in _FLUX_NON_WEIGHT_COMPONENTS if c not in skipped]
        if components.get("policy") != _FLUX_COMPONENT_POLICY:
            problems.append(f"components.policy must be {_FLUX_COMPONENT_POLICY!r}")
        if missing_included:
            problems.append(f"components.included missing {', '.join(missing_included)}")
        if missing_skipped:
            problems.append(f"components.skipped missing {', '.join(missing_skipped)}")

    tensors = metadata.get("tensors")
    if not isinstance(tensors, dict):
        problems.append("missing tensor metadata table")
        return problems

    tensor_names = tuple(tensors.keys())
    for component, prefixes in _FLUX_REQUIRED_TENSOR_PREFIXES.items():
        if not any(name.startswith(prefix) for name in tensor_names for prefix in prefixes):
            pretty = "/".join(prefixes)
            problems.append(f"missing {component} tensors with prefix {pretty}")
        shapeless = [
            name
            for name, info in tensors.items()
            if any(name.startswith(prefix) for prefix in prefixes)
            and (
                not isinstance(info, dict)
                or not isinstance(info.get("shape"), list)
                or len(info["shape"]) == 0
            )
        ]
        if shapeless:
            problems.append(
                f"{component} tensors missing shape metadata: "
                + ", ".join(shapeless[:3])
                + ("..." if len(shapeless) > 3 else "")
            )
    return problems


def _validate_written_flux_knot(path: Path) -> None:
    problems = _validate_flux_knot_metadata(_read_knot_metadata(path))
    if not problems:
        print("[knot] FLUX component validation passed: transformer, VAE, CLIP, T5",
              file=sys.stderr)
        return
    print("ERROR: FLUX KNOT rebuild incomplete; stale transformer-only artifact detected.",
          file=sys.stderr)
    for problem in problems:
        print(f"  - {problem}", file=sys.stderr)
    raise SystemExit(1)

