#   visual.merger.mlp.0.bias         [5120]
#   visual.merger.mlp.2.weight       [2048, 5120]          Linear -> text hidden 2048
#   visual.merger.mlp.2.bias         [2048]
# vision_config: depth=32, hidden=1280, heads=16, intermediate=3420, patch=14,
