# ─────────────────────────────────────────────────────────────────────────────
# Arch + KnotConfig detection from HF config.json
# ─────────────────────────────────────────────────────────────────────────────

def _resolve_rope_theta(cfg: Any, default: float) -> float:
    """rope_theta is a top-level attr for most models, but Llama-3.1/3.2 nest it
    inside `rope_scaling` (rope_type='llama3') and leave the top-level attr unset.
    Prefer the top-level value, fall back to the nested one, then the default.
    (Without this, Llama-3.x knots got rope_theta=10000 instead of 500000 ->
    wrong positional encoding -> finite-but-incoherent output.)"""
    rt = getattr(cfg, "rope_theta", None)
    if rt is None:
        rs = getattr(cfg, "rope_scaling", None)
        if isinstance(rs, dict):
            rt = rs.get("rope_theta")
    return float(rt) if rt is not None else float(default)


def _detect_arch_and_config(hf_cfg: Any, model_id: str) -> tuple[str, dict[str, Any]]:
    """Parse HF config object → (arch_string, knot_config_dict)."""

    # Gemma4 wraps its text config under `text_config`
    raw = hf_cfg
    text_cfg = getattr(raw, "text_config", None) or raw

    archs = getattr(raw, "architectures", None) or []
    mtype = (getattr(raw, "model_type", "") or "").lower().replace("-", "_")

    # ── Gemma4 ────────────────────────────────────────────────────────────────
    if mtype == "gemma4" or any("Gemma4" in a for a in archs):
        hidden      = getattr(text_cfg, "hidden_size", 2560)
        n_layers    = getattr(text_cfg, "num_hidden_layers", 34)
        n_heads     = getattr(text_cfg, "num_attention_heads", 16)
        n_kv_h      = getattr(text_cfg, "num_key_value_heads", n_heads)
        head_dim    = getattr(text_cfg, "head_dim",
                              hidden // n_heads)
        ffn_dim     = getattr(text_cfg, "intermediate_size", hidden * 4)
        vocab       = getattr(text_cfg, "vocab_size", 262144)
        rms_eps     = float(getattr(text_cfg, "rms_norm_eps", 1e-6))
        rope_theta  = float(getattr(text_cfg, "rope_theta", 1_000_000.0))
        softcap     = getattr(text_cfg, "final_logit_softcap", 30.0)
        qpas        = getattr(text_cfg, "query_pre_attn_scalar", None)
        sw_pattern  = getattr(text_cfg, "sliding_window_pattern", None)
        sw_size     = getattr(text_cfg, "sliding_window", None)
        g_head_dim  = getattr(text_cfg, "global_head_dim", None)
        g_kv_heads  = getattr(text_cfg, "global_num_kv_heads", None)
        rope_local  = getattr(text_cfg, "rope_local_base_freq", None)
        rope_scale  = getattr(text_cfg, "rope_scaling", None)
        if isinstance(rope_scale, dict):
            rope_scale = rope_scale.get("factor", None)
        rope_partial = getattr(text_cfg, "rope_partial_rotary_factor", 0.25)

        knot_cfg: dict[str, Any] = {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "gemma4",
        }
        if softcap is not None:
            knot_cfg["final_logit_softcap"] = float(softcap)
        if qpas is not None:
            knot_cfg["query_pre_attn_scalar"] = float(qpas)
        if sw_pattern is not None:
            knot_cfg["sliding_window_pattern"] = int(sw_pattern)
        if sw_size is not None:
            knot_cfg["sliding_window"] = int(sw_size)
        if g_head_dim is not None:
            knot_cfg["global_head_dim"] = int(g_head_dim)
        if g_kv_heads is not None:
            knot_cfg["global_num_kv_heads"] = int(g_kv_heads)
        if rope_local is not None:
            knot_cfg["rope_local_base_freq"] = float(rope_local)
        if rope_scale is not None:
            knot_cfg["rope_scaling_factor"] = float(rope_scale)
        if rope_partial is not None:
            knot_cfg["rope_partial_factor"] = float(rope_partial)

        # ── E4B (Gemma3n-style) per-layer-input-embeddings (PLE) + KV-share ──
        # Gated on the E4B-only config field `hidden_size_per_layer_input`.
        # Plain dense gemma4-31b has none of these, so this block is a no-op
        # there and the dense path is unaffected.
        hp_in = getattr(text_cfg, "hidden_size_per_layer_input", None)
        if hp_in is not None:
            knot_cfg["hidden_size_per_layer_input"] = int(hp_in)
            vp_in = getattr(text_cfg, "vocab_size_per_layer_input", vocab)
            knot_cfg["vocab_size_per_layer_input"] = int(vp_in)
            n_kv_shared = getattr(text_cfg, "num_kv_shared_layers", None)
            if n_kv_shared is not None:
                knot_cfg["num_kv_shared_layers"] = int(n_kv_shared)
            layer_types = getattr(text_cfg, "layer_types", None)
            if layer_types is not None:
                knot_cfg["layer_types"] = list(layer_types)
            # E4B HF default: query_pre_attn_scalar == head_dim (256). The
            # config.json omits it, so stamp it explicitly (matches the
            # runtime's None-fallback 1/sqrt(head_dim), made non-implicit).
            if qpas is None:
                knot_cfg["query_pre_attn_scalar"] = float(head_dim)
            knot_cfg["e4b"] = True

        return "gemma4", knot_cfg

    # ── Gemma3 ────────────────────────────────────────────────────────────────
    elif mtype in ("gemma3", "gemma3_text") or any("Gemma3" in a for a in archs):
        # Gemma3 multimodal (ForConditionalGeneration) nests text dims under
        # text_config; text-only (ForCausalLM) has them directly on raw.
        # raw may also have the vision-encoder's hidden_size (e.g. 1152 for
        # SigLIP) which must NOT be used for the text model. Cascade through
        # text_cfg first, then raw, to handle both layouts.
        def _g3(key, default, *fallbacks):
            for obj in fallbacks:
                if obj is None:
                    continue
                # Direct attribute (PretrainedConfig subclass)
                v = getattr(obj, key, None)
                if v:
                    return v
                # Plain dict (some nested configs are returned as dicts)
                if isinstance(obj, dict):
                    v = obj.get(key)
                    if v:
                        return v
                # __dict__ (catches attrs not exposed as properties)
                if hasattr(obj, "__dict__"):
                    v = obj.__dict__.get(key)
                    if v:
                        return v
                # to_dict() (HuggingFace PretrainedConfig canonical accessor)
                if hasattr(obj, "to_dict"):
                    try:
                        v = obj.to_dict().get(key)
                        if v:
                            return v
                    except Exception:
                        pass
            return default
        import sys as _sys
        _sys.stderr.write(
            f"[debug-gemma3] raw.hidden_size={getattr(raw,'hidden_size','?')} "
            f"raw.num_hidden_layers={getattr(raw,'num_hidden_layers','?')} "
            f"text_cfg type={type(text_cfg).__name__} "
            f"text_cfg.hidden_size={getattr(text_cfg,'hidden_size','?')}\n"
        )
        hidden     = _g3("hidden_size",       1152, text_cfg, raw)
        n_layers   = _g3("num_hidden_layers",    26, text_cfg, raw)
        n_heads    = _g3("num_attention_heads",   4, text_cfg, raw)
        n_kv_h     = _g3("num_key_value_heads", n_heads, text_cfg, raw)
        head_dim   = _g3("head_dim",   hidden // n_heads, text_cfg, raw)
        ffn_dim    = _g3("intermediate_size", hidden * 4, text_cfg, raw)
        vocab      = _g3("vocab_size",          262144, text_cfg, raw)
        rms_eps    = float(_g3("rms_norm_eps",    1e-6, text_cfg, raw))
        # Gemma3 alternates LOCAL sliding-window attention (rope 10000) with
        # GLOBAL full attention (rope 1e6). transformers v5 nests these per
        # attention-type under `rope_parameters`:
        #   {'sliding_attention': {'rope_theta': 10000},
        #    'full_attention':    {'rope_theta': 1000000}}
        # A bare getattr("rope_theta") misses the nesting → returns 10000 for
        # ALL layers, so the global layers get the wrong rope → garbage logits.
        rope_theta = 1_000_000.0   # global (full_attention) default
        rope_local = 10000.0       # local (sliding_attention) default
        rope_params = _g3("rope_parameters", None, text_cfg, raw)
        if isinstance(rope_params, dict):
            fa = rope_params.get("full_attention")
            sa = rope_params.get("sliding_attention")
            if isinstance(fa, dict) and fa.get("rope_theta"):
                rope_theta = float(fa["rope_theta"])
            if isinstance(sa, dict) and sa.get("rope_theta"):
                rope_local = float(sa["rope_theta"])
        else:
            rope_theta = _resolve_rope_theta(text_cfg, 1_000_000.0)
            rl = _g3("rope_local_base_freq", None, text_cfg, raw)
            if rl:
                rope_local = float(rl)
        qpas = _g3("query_pre_attn_scalar", None, text_cfg, raw)
        sw_size = _g3("sliding_window", None, text_cfg, raw)
        # sliding_window_pattern: period to the first global ("full_attention")
        # layer. v5 exposes per-layer `layer_types`; older configs use the scalar.
        sw_pattern = getattr(text_cfg, "sliding_window_pattern", None) or getattr(raw, "sliding_window_pattern", None)
        layer_types = _g3("layer_types", None, text_cfg, raw)
        if sw_pattern is None and isinstance(layer_types, list) and "full_attention" in layer_types:
            sw_pattern = layer_types.index("full_attention") + 1
        softcap = _g3("final_logit_softcapping", None, text_cfg, raw)

        knot_cfg = {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "rope_local_base_freq": rope_local,
            "arch": "gemma3",
        }
        if qpas is not None:
            knot_cfg["query_pre_attn_scalar"] = float(qpas)
        if sw_pattern is not None:
            knot_cfg["sliding_window_pattern"] = int(sw_pattern)
        if sw_size is not None:
            knot_cfg["sliding_window"] = int(sw_size)
        if softcap is not None:
            knot_cfg["final_logit_softcap"] = float(softcap)
        return "gemma3", knot_cfg

    # ── Phi-3 / Phi-3.5 (fused QKV + fused gate_up) ─────────────────────────
    elif mtype in ("phi3", "phi_3") or any("Phi3" in a for a in archs):
        hidden     = getattr(raw, "hidden_size", 3072)
        n_layers   = getattr(raw, "num_hidden_layers", 32)
        n_heads    = getattr(raw, "num_attention_heads", 32)
        n_kv_h     = getattr(raw, "num_key_value_heads", n_heads)
        head_dim   = getattr(raw, "head_dim", hidden // n_heads)
        ffn_dim    = getattr(raw, "intermediate_size", 8192)
        vocab      = getattr(raw, "vocab_size", 32064)
        rms_eps    = float(getattr(raw, "rms_norm_eps", 1e-5))
        rope_theta = float(getattr(raw, "rope_theta", 10000.0))
        return "phi3", {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "phi3",
        }

    # ── GLM-OCR / GLM-4.1V (glm_ocr) — VL: GLM-4 text backbone + Qwen2-VL-style
    #    ViT, both carried into ONE dense knot. The text dims live under
    #    `text_config`, the vision tower under `vision_config`. We stamp
    #    arch="qwen2" so NativeLlamaPipeline drives the (un-fused, sandwich-normed)
    #    text backbone; the vision tower is carried as vit_* (consumed by
    #    model_glm_ocr_vit.rs) and the sandwich norms ride as extra blk_* norms.
    elif mtype in ("glm_ocr", "glm4v", "glm4v_moe") or any(
        a in archs for a in ("GlmOcrForConditionalGeneration",
                             "Glm4vForConditionalGeneration")
    ):
        tc = getattr(raw, "text_config", None) or raw
        hidden     = getattr(tc, "hidden_size", 1536)
        n_layers   = getattr(tc, "num_hidden_layers", 16)
        n_heads    = getattr(tc, "num_attention_heads", 16)
        n_kv_h     = getattr(tc, "num_key_value_heads", 8)
        head_dim   = getattr(tc, "head_dim", hidden // n_heads)
        ffn_dim    = getattr(tc, "intermediate_size", 4608)
        vocab      = getattr(tc, "vocab_size", getattr(raw, "vocab_size", 59392))
        rms_eps    = float(getattr(tc, "rms_norm_eps", 1e-5))
        rope_theta = _resolve_rope_theta(tc, 10000.0)

        vc = getattr(raw, "vision_config", None)
        def _gvc(key, default):
            if vc is None:
                return default
            v = getattr(vc, key, None)
            if v is None and isinstance(vc, dict):
                v = vc.get(key)
            if v is None and hasattr(vc, "to_dict"):
                try:
                    v = vc.to_dict().get(key)
                except Exception:
                    v = None
            return v if v is not None else default

        knot_cfg = {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "qwen2",
            # Vision-tower dims (consumed by model_glm_ocr_vit.rs::GlmOcrVitConfig).
            "vit_depth":               int(_gvc("depth", 24)),
            "vit_hidden_size":         int(_gvc("hidden_size", 1024)),
            "vit_num_heads":           int(_gvc("num_heads", 16)),
            "vit_intermediate_size":   int(_gvc("intermediate_size", 4096)),
            "vit_patch_size":          int(_gvc("patch_size", 14)),
            "vit_temporal_patch_size": int(_gvc("temporal_patch_size", 2)),
            "vit_in_chans":            int(_gvc("in_channels", _gvc("in_chans", 3))),
            "vit_spatial_merge_size":  int(_gvc("spatial_merge_size", 2)),
            "vit_out_hidden_size":     int(_gvc("out_hidden_size", hidden)),
            # GLM-OCR merger SwiGLU inner dim == text intermediate_size.
            "vit_merger_intermediate_size": int(_gvc("intermediate_size_text", ffn_dim)),
        }
        return "glm_ocr", knot_cfg

    # ── GLM-4 (THUDM ChatGLM4, fused QKV + SwiGLU) ───────────────────────────
    # GLM-4 uses transformer.encoder.* naming. Tensors map to Phi-3-compatible
    # KNOT keys so Phi3Pipeline (which accepts arch="glm4") can load them.
    elif mtype in ("chatglm", "glm", "glm4") or any("ChatGLM" in a for a in archs):
        hidden     = getattr(raw, "hidden_size", 4096)
        n_layers   = getattr(raw, "num_hidden_layers", 40)
        n_heads    = getattr(raw, "num_attention_heads", 32)
        n_kv_h     = getattr(raw, "multi_query_group_num",
                             getattr(raw, "num_key_value_heads", n_heads))
        head_dim   = getattr(raw, "head_dim", hidden // n_heads)
        # GLM-4 intermediate_size is per-half (gate OR up), not combined
        ffn_dim    = getattr(raw, "ffn_hidden_size",
                             getattr(raw, "intermediate_size", 13696))
        vocab      = getattr(raw, "padded_vocab_size",
                             getattr(raw, "vocab_size", 151552))
        rms_eps    = float(getattr(raw, "layernorm_epsilon", 1e-5))
        rope_theta = float(getattr(raw, "rope_theta", 10000.0))
        return "glm4", {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "glm4",
        }

    # ── Mixtral MoE ───────────────────────────────────────────────────────────
    elif mtype == "mixtral" or any("Mixtral" in a for a in archs):
        hidden       = getattr(raw, "hidden_size", 4096)
        n_layers     = getattr(raw, "num_hidden_layers", 32)
        n_heads      = getattr(raw, "num_attention_heads", 32)
        n_kv_h       = getattr(raw, "num_key_value_heads", 8)
        head_dim     = getattr(raw, "head_dim", hidden // n_heads)
        ffn_dim      = getattr(raw, "intermediate_size", 14336)
        vocab        = getattr(raw, "vocab_size", 32000)
        rms_eps      = float(getattr(raw, "rms_norm_eps", 1e-5))
        rope_theta   = float(getattr(raw, "rope_theta", 1_000_000.0))
        n_experts    = getattr(raw, "num_local_experts", 8)
        top_k        = getattr(raw, "num_experts_per_tok", 2)
        return "mixtral", {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "mixtral",
            "num_experts": n_experts, "num_experts_per_tok": top_k,
        }

    # ── Qwen3-MoE ─────────────────────────────────────────────────────────────
    elif mtype in ("qwen3_moe", "qwen3moe") or any("Qwen3Moe" in a for a in archs):
        hidden       = getattr(raw, "hidden_size", 2048)
        n_layers     = getattr(raw, "num_hidden_layers", 94)
        n_heads      = getattr(raw, "num_attention_heads", 16)
        n_kv_h       = getattr(raw, "num_key_value_heads", 8)
        head_dim     = getattr(raw, "head_dim", hidden // n_heads)
        ffn_dim      = getattr(raw, "moe_intermediate_size",
                               getattr(raw, "intermediate_size", hidden * 4))
        vocab        = getattr(raw, "vocab_size", 151936)
        rms_eps      = float(getattr(raw, "rms_norm_eps", 1e-6))
        rope_theta   = float(getattr(raw, "rope_theta", 1_000_000.0))
        n_experts    = getattr(raw, "num_experts", 128)
        top_k        = getattr(raw, "num_experts_per_tok", 8)

        return "qwen3moe", {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "qwen3moe",
            "num_experts": n_experts, "num_experts_per_tok": top_k,
        }

    # ── FLUX DiT (black-forest-labs/FLUX.1-dev, FLUX.1-schnell) ─────────────
    elif mtype in ("flux",) or any("Flux" in a for a in archs):
        hidden   = getattr(raw, "hidden_size",      3072)
        n_heads  = getattr(raw, "num_attention_heads", 24)
        n_dbl    = getattr(raw, "num_double_layers",   19)
        n_sgl    = getattr(raw, "num_single_layers",   38)
        in_ch    = getattr(raw, "in_channels",         64)
        txt_dim  = getattr(raw, "joint_attention_dim", 4096)
        pool_dim = getattr(raw, "pooled_projection_dim", 768)
        return "flux", {
            "hidden_dim": hidden, "num_layers": n_dbl,
            "num_heads": n_heads, "num_kv_heads": n_heads,
            "head_dim": hidden // n_heads, "intermediate_size": hidden * 4,
            "vocab_size": 0, "arch": "flux",
            "num_double_blocks": n_dbl, "num_single_blocks": n_sgl,
            "in_channels": in_ch, "txt_dim": txt_dim, "pool_dim": pool_dim,
        }

    # ── BLIP-2 (Salesforce/blip2-*) ──────────────────────────────────────────
    # LM is OPT-based under language_model.model.decoder.*
    # language_model. prefix is stripped in _map_name; decoder patterns cover it.
    elif mtype in ("blip-2", "blip_2") or any("Blip2" in a for a in archs):
        lm_cfg  = getattr(raw, "language_model_config", None) or raw
        hidden  = getattr(lm_cfg, "hidden_size",  2560)
        n_heads = getattr(lm_cfg, "num_attention_heads", 32)
        n_layers = getattr(lm_cfg, "num_hidden_layers", 32)
        vocab   = getattr(lm_cfg, "vocab_size", 50272)
        ffn_dim = getattr(lm_cfg, "ffn_dim", hidden * 4)
        return "blip2", {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_heads,
            "head_dim": hidden // n_heads, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "arch": "blip2",
        }

    # ── Whisper (openai/whisper-*) ────────────────────────────────────────────
    elif mtype == "whisper" or any("Whisper" in a for a in archs):
        d_model    = getattr(raw, "d_model", 1280)
        enc_layers = getattr(raw, "encoder_layers", 32)
        dec_layers = getattr(raw, "decoder_layers", 4)
        enc_heads  = getattr(raw, "encoder_attention_heads", 20)
        dec_heads  = getattr(raw, "decoder_attention_heads", 20)
        vocab      = getattr(raw, "vocab_size", 51866)
        ffn_dim    = getattr(raw, "encoder_ffn_dim", d_model * 4)
        return "whisper", {
            "hidden_dim": d_model, "num_layers": dec_layers,
            "num_heads": dec_heads, "num_kv_heads": dec_heads,
            "head_dim": d_model // dec_heads, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "arch": "whisper",
            "encoder_layers": enc_layers, "encoder_heads": enc_heads,
        }

    # ── LLaVA / Idefics3 / SmolVLM2: read dims from text_config sub-config ──
    elif mtype in ("llava", "idefics3", "smolvlm") or any(
        a in archs for a in ("LlavaForConditionalGeneration",
                             "Idefics3ForConditionalGeneration",
                             "SmolVLMForConditionalGeneration")
    ):
        text = getattr(raw, "text_config", raw)
        hidden    = getattr(text, "hidden_size", 4096)
        n_layers  = getattr(text, "num_hidden_layers", 32)
        n_heads   = getattr(text, "num_attention_heads", 32)
        n_kv_h    = getattr(text, "num_key_value_heads", n_heads)
        head_dim  = getattr(text, "head_dim", hidden // n_heads)
        ffn_dim   = getattr(text, "intermediate_size", hidden * 4)
        vocab     = getattr(text, "vocab_size", 32000)
        rms_eps   = float(getattr(text, "rms_norm_eps", 1e-5))
        rope_theta = _resolve_rope_theta(text, 10000.0)
        return "llama", {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "llama",
        }

    # ── LlamaForCausalLM (SmolLM2, TinyLlama, etc.) ──────────────────────────
    elif mtype == "mistral" or any("Mistral" in a for a in archs):
        hidden     = getattr(raw, "hidden_size", 6144)
        n_layers   = getattr(raw, "num_hidden_layers", 56)
        n_heads    = getattr(raw, "num_attention_heads", 48)
        n_kv_h     = getattr(raw, "num_key_value_heads", n_heads)
        head_dim   = getattr(raw, "head_dim", hidden // n_heads)
        ffn_dim    = getattr(raw, "intermediate_size", 16384)
        vocab      = getattr(raw, "vocab_size", 32768)
        rms_eps    = float(getattr(raw, "rms_norm_eps", 1e-5))
        rope_theta = _resolve_rope_theta(raw, 1_000_000.0)
        knot_cfg = {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "llama",
        }
        sliding_window = getattr(raw, "sliding_window", None)
        if sliding_window is not None:
            knot_cfg["sliding_window"] = int(sliding_window)
        return "llama", knot_cfg

    # ── LlamaForCausalLM (SmolLM2, TinyLlama, etc.) ──────────────────────────
    elif mtype == "llama" or any("Llama" in a for a in archs):
        hidden     = getattr(raw, "hidden_size", 1024)
        n_layers   = getattr(raw, "num_hidden_layers", 24)
        n_heads    = getattr(raw, "num_attention_heads", 16)
        n_kv_h     = getattr(raw, "num_key_value_heads", n_heads)
        head_dim   = getattr(raw, "head_dim", hidden // n_heads)
        ffn_dim    = getattr(raw, "intermediate_size", hidden * 4)
        vocab      = getattr(raw, "vocab_size", 49152)
        rms_eps    = float(getattr(raw, "rms_norm_eps", 1e-5))
        rope_theta = _resolve_rope_theta(raw, 10000.0)
        return "llama", {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "llama",
        }

    # ── Qwen2.5-VL / Qwen2-VL (text backbone = Qwen2 + carried vision tower) ──
    # The text dims live at the TOP LEVEL of the Qwen2_5_VLConfig (hidden_size
    # 2048, num_hidden_layers 36, num_attention_heads 16, num_key_value_heads 2
    # for the 3B). Older knots fell through to the default qwen2 branch which
    # read these correctly, BUT the vision tower (visual.*) was dropped because
    # no pattern matched, AND tie_word_embeddings=True means output.weight is
    # the embedding table (no separate lm_head). We carry the vision tower here
    # and stamp arch="qwen2" so NativeLlamaPipeline drives the text backbone.
    elif mtype in ("qwen2_5_vl", "qwen2_vl") or any(
        a in archs for a in ("Qwen2_5_VLForConditionalGeneration",
                             "Qwen2VLForConditionalGeneration")
    ):
        # Multimodal configs may nest text dims under text_config in newer
        # transformers; cascade text_cfg -> raw so both layouts resolve.
        tc = getattr(raw, "text_config", None) or raw
        hidden     = getattr(tc, "hidden_size", 2048)
        n_layers   = getattr(tc, "num_hidden_layers", 36)
        n_heads    = getattr(tc, "num_attention_heads", 16)
        n_kv_h     = getattr(tc, "num_key_value_heads", 2)
        head_dim   = getattr(tc, "head_dim", hidden // n_heads)
        ffn_dim    = getattr(tc, "intermediate_size", 11008)
        vocab      = getattr(tc, "vocab_size", getattr(raw, "vocab_size", 151936))
        rms_eps    = float(getattr(tc, "rms_norm_eps", 1e-6))
        rope_theta = _resolve_rope_theta(tc, 1_000_000.0)

        vc = getattr(raw, "vision_config", None)
        def _vc(key, default):
            if vc is None:
                return default
            v = getattr(vc, key, None)
            if v is None and isinstance(vc, dict):
                v = vc.get(key)
            if v is None and hasattr(vc, "to_dict"):
                try:
                    v = vc.to_dict().get(key)
                except Exception:
                    v = None
            return v if v is not None else default

        knot_cfg = {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "qwen2",
            # Vision-tower dims (consumed by model_qwen2vl_vit.rs). Prefixed
            # vit_* so they ride alongside the text config in the same block.
            "vit_depth":               int(_vc("depth", 32)),
            "vit_hidden_size":         int(_vc("hidden_size", 1280)),
            "vit_num_heads":           int(_vc("num_heads", 16)),
            "vit_intermediate_size":   int(_vc("intermediate_size", 3420)),
            "vit_patch_size":          int(_vc("patch_size", 14)),
            "vit_temporal_patch_size": int(_vc("temporal_patch_size", 2)),
            "vit_in_chans":            int(_vc("in_chans", 3)),
            "vit_spatial_merge_size":  int(_vc("spatial_merge_size", 2)),
            "vit_window_size":         int(_vc("window_size", 112)),
            "vit_out_hidden_size":     int(_vc("out_hidden_size", hidden)),
            "vit_fullatt_block_indexes": list(_vc("fullatt_block_indexes", [7, 15, 23, 31])),
        }
        return "qwen2_5_vl", knot_cfg

    # ── Qwen3-TTS (talker Qwen3 LM + carried codec DECODER) ──────────────────
    # forkjoin-ai/qwen3-tts-12hz-0.6b-base. The TTS model has TWO weight files:
    #   model.safetensors            talker.* (Qwen3 LM, hidden 1024, 28 layers,
    #                                 q_norm/k_norm, head_dim 128, GQA 16/8),
    #                                 talker.codec_head (codec-token logits),
    #                                 code_predictor.* (depth MTP, 16 codes/frame)
    #   speech_tokenizer/model.safetensors   decoder.* (RVQ + transformer +
    #                                 SEANet conv decoder; codec tokens → 24kHz).
    # We stamp arch="qwen3" so the talker drives through NativeLlama's Qwen3 path
    # (per-head q_norm/k_norm already supported), and CARRY the codec decoder's
    # decoder.* tensors under the `tts_codec_*` prefix (consumed by
    # model_qwen3_tts_codec.rs). Mirrors the qwen2_5_vl vision-tower carry.
    elif mtype == "qwen3_tts" or any("Qwen3TTS" in a for a in archs):
        tk = getattr(raw, "talker_config", None) or raw
        def _tk(key, default):
            v = getattr(tk, key, None)
            if v is None and isinstance(tk, dict):
                v = tk.get(key)
            return v if v is not None else default
        hidden   = int(_tk("hidden_size", 1024))
        n_layers = int(_tk("num_hidden_layers", 28))
        n_heads  = int(_tk("num_attention_heads", 16))
        n_kv_h   = int(_tk("num_key_value_heads", 8))
        head_dim = int(_tk("head_dim", 128))
        ffn_dim  = int(_tk("intermediate_size", 3072))
        # talker codec vocab (codec_head / codec_embedding): 3072.
        vocab    = int(_tk("vocab_size", 3072))
        rms_eps  = float(_tk("rms_norm_eps", 1e-6))
        rope_theta = float(_tk("rope_theta", 1_000_000.0))
        knot_cfg = {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "qwen3",
            # codec decoder dims (consumed by model_qwen3_tts_codec.rs). Defaults
            # track speech_tokenizer/config.json (12hz, 16 quantizers, 1920 ups).
            "tts_codec_num_quantizers": 16,
            "tts_codec_codebook_size": 2048,
            "tts_codec_codebook_dim": 256,
            "tts_codec_latent_dim": 512,
            "tts_codec_decode_upsample_rate": 1920,
            "tts_codec_sample_rate": 24000,
            "tts_codec_frame_rate": 12.5,
            # talker text→codec path (consumed by model_qwen3_tts_talker.rs). The
            # codec vocab above (vocab_size=3072) is the talker codec_head /
            # group-0 head; the code_predictor emits groups 1..15 (vocab 2048).
            "tts_talker_text_vocab_size": int(_tk("text_vocab_size", 151936)),
            "tts_talker_text_hidden_size": int(_tk("text_hidden_size", 2048)),
            "tts_talker_num_code_groups": int(_tk("num_code_groups", 16)),
            "tts_talker_code_predictor_layers": 5,
            "tts_talker_codec_bos_id": int(_tk("codec_bos_id", 2149)),
            "tts_talker_codec_eos_id": int(_tk("codec_eos_token_id", 2150)),
            "tts_talker_codec_pad_id": int(_tk("codec_pad_id", 2148)),
        }
        return "qwen3_tts", knot_cfg

    # ── Qwen2 / Qwen3 / StableLM / DeepSeek-R1-Distill / default ─────────────
    else:
        hidden     = getattr(raw, "hidden_size", 1536)
        n_layers   = getattr(raw, "num_hidden_layers", 28)
        n_heads    = getattr(raw, "num_attention_heads", 12)
        n_kv_h     = getattr(raw, "num_key_value_heads", n_heads)
        head_dim   = getattr(raw, "head_dim", hidden // n_heads)
        ffn_dim    = getattr(raw, "intermediate_size", hidden * 4)
        vocab      = getattr(raw, "vocab_size", 151936)
        rms_eps    = float(getattr(raw, "rms_norm_eps", 1e-6))
        # transformers v5 nests rope_theta under rope_scaling/rope_parameters on
        # Qwen2Config, so a bare getattr silently returns the 1e6 default — wrong
        # for qwen2-family models that use 10000 (e.g. DeepSeek-R1-Distill-Qwen-1.5B,
        # whose Paris argmax flipped to ' invested' until this was fixed). Use the
        # nested-aware resolver (same fix as the Llama-3.x branches).
        rope_theta = _resolve_rope_theta(raw, 1_000_000.0)
        return "qwen2", {
            "hidden_dim": hidden, "num_layers": n_layers,
            "num_heads": n_heads, "num_kv_heads": n_kv_h,
            "head_dim": head_dim, "intermediate_size": ffn_dim,
            "vocab_size": vocab, "rms_norm_eps": rms_eps,
            "rope_theta": rope_theta, "arch": "qwen2",
        }


# ─────────────────────────────────────────────────────────────────────────────
# Tensor mapping
# ─────────────────────────────────────────────────────────────────────────────

def _split_flux_component_name(hf_name: str, source_component: str | None) -> tuple[str | None, str]:
    if source_component in _FLUX_WEIGHT_COMPONENTS:
        return source_component, hf_name
    for component in _FLUX_WEIGHT_COMPONENTS:
        prefix = component + "."
        if hf_name.startswith(prefix):
            return component, hf_name[len(prefix):]
    return source_component, hf_name


def _map_flux_aux_name(hf_name: str, component: str) -> str | None:
    prefix = _FLUX_AUX_CANON_PREFIXES.get(component)
    if prefix is None:
        return None
    return f"{prefix}.{hf_name}"


def _map_name(hf_name: str, arch: str, source_component: str | None = None) -> str | None:
    """Return the canonical KNOT name for an HF tensor, or None to skip."""
    # ── Qwen3-TTS: talker LM (model.safetensors) + codec DECODER ──────────────
    #    (speech_tokenizer/model.safetensors). Handled FIRST because both files'
    #    namespaces are TTS-specific and must not collide with the generic
    #    model.* rewrites below. Encoder/speaker_encoder/code_predictor/text_*
    #    are intentionally dropped for the codec-gate path (carried later for the
    #    end-to-end talker path).
    if arch == "qwen3_tts":
        # Codec DECODER (speech_tokenizer file). Carry only decoder.* — the
        # encoder.* is speech-IN. KnotWriter joins '.'→'_', so we emit dotted
        # names; the runtime reads them as tts_codec_<dots-as-underscores>.
        if hf_name.startswith("decoder."):
            return "tts_codec." + hf_name[len("decoder."):]
        if hf_name.startswith("encoder.") or hf_name.startswith("speaker_encoder."):
            return None  # speech-IN encoder / speaker embedding — not for TTS-out

        # Talker LM (model.safetensors). Rewrite talker.* → the generic LM
        # namespace so the standard _GLOBALS + _LAYER_PATTERNS below apply.
        if hf_name == "talker.model.codec_embedding.weight":
            return "token_embd.weight"          # codec tokens are the LM inputs
        if hf_name == "talker.codec_head.weight":
            return "output.weight"              # codec-token logits head
        if hf_name == "talker.model.norm.weight":
            return "output_norm.weight"

        # ── End-to-end text→codec talker path (carried under tts_talker_*) ──────
        # Required for the autoregressive text→codec loop (model_qwen3_tts_talker.rs):
        #   talker.model.text_embedding            text-token input table (151936×2048)
        #   talker.text_projection.linear_fc{1,2}  2048→2048→1024 text adapter
        #   talker.code_predictor.*                5-layer depth-MTP transformer +
        #                                          15 per-group lm_heads / codec_embeds
        # KnotWriter joins '.'→'_', so dotted names become tts_talker_<...>.
        if hf_name == "talker.model.text_embedding.weight":
            return "tts_talker.text_embedding.weight"
        if hf_name.startswith("talker.text_projection."):
            return "tts_talker.text_projection." + hf_name[len("talker.text_projection."):]
        if hf_name.startswith("talker.code_predictor."):
            return "tts_talker.code_predictor." + hf_name[len("talker.code_predictor."):]

        if hf_name.startswith("talker.model.layers."):
            hf_name = "model.layers." + hf_name[len("talker.model.layers."):]
            # fall through to the standard layer patterns below.
        elif hf_name.startswith("talker."):
            # Any other talker.* (unmodeled buffers) — drop.
            return None

    # ── GLM-OCR (glm_ocr): vision tower (model.visual.*) + GLM sandwich norms ──
    # Handled BEFORE the generic prefix-strip so model.visual.* is not mangled.
    # The text backbone (model.language_model.layers.* / embed_tokens / norm /
    # lm_head) is stripped to model.* below and matched by the standard patterns;
    # the fused mlp.gate_up_proj is SPLIT in the encode loop, not here.
    if arch == "glm_ocr":
        if hf_name in _GLM_OCR_VIT_GLOBALS:
            return _GLM_OCR_VIT_GLOBALS[hf_name]
        for pat, tmpl in _GLM_OCR_VIT_LAYER_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        # Any other model.visual.* tensor is unmodeled — drop it.
        if hf_name.startswith("model.visual."):
            return None
        # GLM sandwich norms (post_self_attn / post_mlp) — match against the
        # language_model namespace by temporarily normalizing the prefix.
        _norm_name = hf_name
        if _norm_name.startswith("model.language_model.layers."):
            _norm_name = "model.layers." + _norm_name[len("model.language_model.layers."):]
        for pat, tmpl in _GLM_OCR_TEXT_LAYER_PATTERNS:
            m = pat.match(_norm_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        # Multi-Token-Prediction (nextn) layer tensors are inference-irrelevant.
        # They live on the LAST language_model layer index (== num_hidden_layers)
        # and carry eh_proj / enorm / hnorm / embed_tokens / shared_head. Drop.
        if re.search(r"\.(eh_proj|enorm|hnorm|shared_head)\.", hf_name):
            return None
        if re.match(r"^model\.language_model\.layers\.\d+\.embed_tokens\.weight$", hf_name):
            return None
        # Everything else (text q/k/v/o, input_layernorm, post_attention_layernorm,
        # gate/up/down, embed_tokens, norm, lm_head) falls through to the standard
        # prefix-strip + _GLOBALS + _LAYER_PATTERNS below.

    # SmolVLM (SmolVLMForConditionalGeneration): text weights at model.text_model.*
    # Actual keys: model.text_model.layers.N.*, model.text_model.embed_tokens.weight
    if hf_name.startswith("model.text_model."):
        hf_name = "model." + hf_name[len("model.text_model."):]

    # Idefics3: LM weights at model.language_model.model.* (double-nested)
    # Some variants: model.language_model.* (single-nested)
    elif hf_name.startswith("model.language_model.model."):
        hf_name = "model." + hf_name[len("model.language_model.model."):]
    elif hf_name.startswith("model.language_model."):
        hf_name = "model." + hf_name[len("model.language_model."):]

    # Gemma3/4 and LLaVA multimodal wrap the LM under language_model.*
    if hf_name.startswith("language_model."):
        hf_name = hf_name[len("language_model."):]

    # ── Gemma E4B (Gemma3n-style) per-layer-input (PLE) TEXT tensors ──────────
    # These ride alongside the standard gemma4 backbone but the generic patterns
    # don't know them, so map them to the exact names the E4B path in
    # model_gemma4.rs resolves. Dense gemma4-31b has none of these, so the
    # patterns simply never match there (no effect on the dense path).
    if arch == "gemma4":
        if hf_name == "model.embed_tokens_per_layer.weight":
            return "embed_tokens_per_layer.weight"
        if hf_name == "model.per_layer_model_projection.weight":
            return "per_layer_model_projection.weight"
        if hf_name == "model.per_layer_projection_norm.weight":
            return "per_layer_projection_norm.weight"
        _ple = (
            (r"^model\.layers\.(\d+)\.per_layer_input_gate\.weight$",
             "blk.{n}.per_layer_input_gate.weight"),
            (r"^model\.layers\.(\d+)\.per_layer_projection\.weight$",
             "blk.{n}.per_layer_projection.weight"),
            (r"^model\.layers\.(\d+)\.post_per_layer_input_norm\.weight$",
             "blk.{n}.post_per_layer_input_norm.weight"),
            (r"^model\.layers\.(\d+)\.layer_scalar$",
             "blk.{n}.layer_output_scale.weight"),
        )
        for _pat, _tmpl in _ple:
            _m = re.match(_pat, hf_name)
            if _m:
                return _tmpl.replace("{n}", _m.group(1))

    # ── FLUX DiT: strip model.diffusion_model. prefix, then match ──────────
    if arch == "flux":
        flux_component, hf_name = _split_flux_component_name(hf_name, source_component)
        if flux_component in _FLUX_AUX_CANON_PREFIXES:
            return _map_flux_aux_name(hf_name, flux_component)

        if flux_component == "transformer" and hf_name.startswith("transformer."):
            hf_name = hf_name[len("transformer."):]
        for pfx in ("model.diffusion_model.", "diffusion_model."):
            if hf_name.startswith(pfx):
                hf_name = hf_name[len(pfx):]
                break
        if hf_name in _FLUX_GLOBALS:
            return _FLUX_GLOBALS[hf_name]
        if hf_name in _FLUX_DIFFUSERS_GLOBALS:
            return _FLUX_DIFFUSERS_GLOBALS[hf_name]
        for pat, tmpl in _FLUX_DBL_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        for pat, tmpl in _FLUX_SGL_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        for pat, tmpl in _FLUX_DIFFUSERS_DBL_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        for pat, tmpl in _FLUX_DIFFUSERS_SGL_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        return None

    # ── BLIP-2 OPT LM: model.decoder.* namespace ──────────────────────────
    if arch == "blip2":
        if hf_name in _BLIP2_GLOBALS:
            return _BLIP2_GLOBALS[hf_name]
        for pat, tmpl in _BLIP2_LAYER_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        return None

    # ── Whisper: encoder-decoder, separate pattern tables ──────────────────
    if arch == "whisper":
        if hf_name in _WHISPER_GLOBALS:
            return _WHISPER_GLOBALS[hf_name]
        for pat, tmpl in _WHISPER_ENC_LAYER_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        for pat, tmpl in _WHISPER_DEC_LAYER_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        return None

    # ── GLM-4: entirely different HF namespace ─────────────────────────────
    if arch == "glm4":
        if hf_name in _GLM4_GLOBALS:
            return _GLM4_GLOBALS[hf_name]
        for pat, tmpl in _GLM4_LAYER_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        return None

    # ── Qwen2.5-VL / Qwen2-VL vision tower (visual.*) ──────────────────────
    # Text backbone (model.layers.* / model.embed_tokens / model.norm) falls
    # through to the standard _GLOBALS + _LAYER_PATTERNS below — only the
    # vision tower is special-cased here.
    if arch == "qwen2_5_vl":
        if hf_name in _QWEN2VL_VIT_GLOBALS:
            return _QWEN2VL_VIT_GLOBALS[hf_name]
        for pat, tmpl in _QWEN2VL_VIT_LAYER_PATTERNS:
            m = pat.match(hf_name)
            if m:
                return tmpl.replace("{n}", m.group(1))
        # Drop the (huge, video-only) full-attention RoPE buffers + any other
        # visual.* tensor we don't model; the text branch handles model.*.

    # ── Standard global tensors ────────────────────────────────────────────
    if hf_name in _GLOBALS:
        return _GLOBALS[hf_name]

    # ── Standard layer patterns (shared by all model.layers.* archs) ──────
    for pat, tmpl in _LAYER_PATTERNS:
        m = pat.match(hf_name)
        if m:
            return tmpl.replace("{n}", m.group(1))

    # ── Qwen3-MoE expert + router patterns ────────────────────────────────
    if arch == "qwen3moe":
        for pat, tmpl in _MOE_LAYER_PATTERNS:
            m = pat.match(hf_name)
            if m:
                canon = tmpl.replace("{n}", m.group(1))
                if len(m.groups()) >= 2:
                    canon = canon.replace("{e}", m.group(2))
                return canon

    # ── Mixtral MoE expert + router patterns ──────────────────────────────
    if arch == "mixtral":
        for pat, tmpl in _MIXTRAL_MOE_PATTERNS:
            m = pat.match(hf_name)
            if m:
                canon = tmpl.replace("{n}", m.group(1))
                if len(m.groups()) >= 2:
                    canon = canon.replace("{e}", m.group(2))
                return canon

    return None


# ─────────────────────────────────────────────────────────────────────────────
# Main encoding loop
# ─────────────────────────────────────────────────────────────────────────────

def encode(model_id: str, output_path: Path, *,
           hf_token: str | None = None,
           max_layers: int | None = None,
           revision: str = "main",
           capture_all: bool = False) -> None:
    try:
        from transformers import AutoConfig
    except ImportError:
        print("ERROR: transformers required.  pip install transformers", file=sys.stderr)
        sys.exit(1)

    print(f"[knot] loading config for {model_id}", file=sys.stderr)
    try:
        hf_cfg = AutoConfig.from_pretrained(
            model_id, trust_remote_code=True,
            token=hf_token, revision=revision,
        )
    except (ValueError, OSError):
        # Diffusers models (FLUX, etc.) have no standard model_type at repo root.
        # Try the transformer sub-directory config, then fall back to a stub.
        try:
            hf_cfg = AutoConfig.from_pretrained(
                f"{model_id}/transformer", trust_remote_code=True,
                token=hf_token, revision=revision,
            )
        except Exception:
            from types import SimpleNamespace
            # Custom model_type unknown to this transformers version (e.g.
            # qwen3_tts): read the repo's config.json directly and present it as a
            # namespace so _detect_arch_and_config can branch on model_type + raw
            # fields without a registered config class.
            try:
                local_cfg = _load_local_config_namespace(model_id)
                if local_cfg is not None:
                    hf_cfg = local_cfg
                else:
                    from huggingface_hub import hf_hub_download
                    _cfg_path = hf_hub_download(
                        model_id, "config.json", token=hf_token, revision=revision)
                    with open(_cfg_path) as _f:
                        hf_cfg = SimpleNamespace(**json.load(_f))
            except Exception:
                # Known FLUX stub (diffusers, no root model_type), else re-raise.
                if "FLUX" in model_id or "flux" in model_id.lower():
                    hf_cfg = SimpleNamespace(model_type="flux", architectures=["FluxTransformer2DModel"])
                else:
                    raise
    arch, knot_cfg = _detect_arch_and_config(hf_cfg, model_id)

    num_layers = knot_cfg["num_layers"]
    if max_layers is not None:
        num_layers = min(num_layers, max_layers)
        knot_cfg = dict(knot_cfg, num_layers=num_layers)
        print(f"[knot] --max-layers {max_layers}: encoding {num_layers} layers only",
              file=sys.stderr)

    print(f"[knot] arch={arch!r}  layers={num_layers}  hidden={knot_cfg['hidden_dim']}",
          file=sys.stderr)

    name_slug = model_id.split("/")[-1].lower()
    writer = KnotWriter(name_slug, arch, knot_cfg,
                        components=_component_metadata_for_arch(arch),
                        output_path=output_path)

    try:
        from huggingface_hub import snapshot_download
        from safetensors import safe_open
        import glob as _glob
    except ImportError:
        print("ERROR: huggingface_hub safetensors required.", file=sys.stderr)
        sys.exit(1)

    if _local_model_dir(model_id) is None:
        print(f"[knot] downloading weights from {model_id}", file=sys.stderr)
    else:
        print(f"[knot] reading local weights from {model_id}", file=sys.stderr)
    local_dir = _resolve_model_dir(
        model_id, arch=arch, snapshot_download=snapshot_download,
        revision=revision, hf_token=hf_token,
    )
    # Transformers models: weights at root. Diffusers FLUX: carry transformer,
    # VAE, CLIP, and T5 text-encoder shards as separate component namespaces.
    shard_files = _shard_files_for_arch(local_dir, arch, _glob)
    # Qwen3-TTS carries the codec decoder in a SEPARATE sub-directory shard
    # (speech_tokenizer/model.safetensors); fold it into the shard list so the
    # decoder.* tensors are mapped to tts_codec_* alongside the talker.
    if arch == "qwen3_tts":
        st_shards = sorted(_glob.glob(f"{local_dir}/speech_tokenizer/*.safetensors"))
        if not st_shards:
            print("ERROR: qwen3_tts: no speech_tokenizer/*.safetensors found "
                  f"in {local_dir} — codec decoder cannot be carried.", file=sys.stderr)
            sys.exit(1)
        shard_files = shard_files + st_shards
        print(f"[knot] qwen3_tts: +{len(st_shards)} speech_tokenizer shard(s) "
              "for the codec decoder", file=sys.stderr)
    if not shard_files:
        print(f"ERROR: no .safetensors files found in {local_dir}", file=sys.stderr)
        sys.exit(1)

    n_written = 0
    n_skipped = 0

    # GLM-4 uses transformer.encoder.layers.*; GLM-OCR uses
    # model.language_model.layers.* — everything else is model.layers.*.
    if arch == "glm4":
        layer_re = re.compile(r"^transformer\.encoder\.layers\.(\d+)\.")
    elif arch == "glm_ocr":
        layer_re = re.compile(r"^model\.language_model\.layers\.(\d+)\.")
    else:
        layer_re = re.compile(r"^model\.layers\.(\d+)\.")

    # Qwen2.5-VL / Qwen2-VL tie word embeddings (tie_word_embeddings=True): the
    # HF state_dict has NO lm_head.weight, so token_embd.weight must ALSO be
    # written as output.weight or the LM forward gets an all-zero lm_head ->
    # degenerate argmax. (This is the documented "zeroed token_embd" failure
    # mode — really a missing output.weight + an embed table that the default
    # qwen2 branch carried but the runtime read against a wrong-dim config.)
    # We detect "tie" generically and emit the duplicate from the embed table.
    tie_embeddings = bool(getattr(hf_cfg, "tie_word_embeddings", False)) or (
        getattr(hf_cfg, "text_config", None) is not None
        and bool(getattr(getattr(hf_cfg, "text_config"), "tie_word_embeddings", False))
    )
    embed_arr_for_tie = None  # captured during the loop if tie + no lm_head seen
    saw_lm_head = False

    for shard_path in shard_files:
        source_component = _flux_component_for_shard(local_dir, shard_path) if arch == "flux" else None
        with safe_open(shard_path, framework="numpy", device="cpu") as f:
            for hf_name in f.keys():
                m = layer_re.match(hf_name)
                if m and int(m.group(1)) >= num_layers:
                    continue

                if hf_name in ("lm_head.weight", "model.lm_head.weight"):
                    saw_lm_head = True

                # ── GLM-OCR: split the fused MLP gate_up_proj into separate
                #    ffn_gate + ffn_up so NativeLlama's qwen2 SwiGLU path (which
                #    expects DISTINCT gate/up tensors) drives it. The fused tensor
                #    is [2*inter, hidden] = [gate-rows | up-rows] stacked on dim 0.
                if arch == "glm_ocr":
                    gu = re.match(
                        r"^model\.language_model\.layers\.(\d+)\.mlp\.gate_up_proj\.weight$",
                        hf_name,
                    )
                    if gu:
                        n = int(gu.group(1))
                        if n >= num_layers:
                            continue
                        full = _to_f32(f.get_tensor(hf_name))  # [2*inter, hidden]
                        inter = full.shape[0] // 2
                        gate = full[:inter, :]
                        up = full[inter:, :]
                        writer.add_auto(f"blk_{n}_ffn_gate.weight", gate)
                        writer.add_auto(f"blk_{n}_ffn_up.weight", up)
                        n_written += 2
                        continue

                canon = _map_name(hf_name, arch, source_component)
                if canon is None:
                    if capture_all:
                        # --capture-all: keep unmapped tensors (e.g. the E4B
                        # vision/audio towers) verbatim so the knot is
                        # multimodal-ready, even though no pipeline runs them
                        # yet. add_auto sanitizes dots->underscores.
                        canon = hf_name
                    else:
                        n_skipped += 1
                        continue

                # ── Large-tensor streaming Q8 (avoid whole-tensor OOM) ────────
                # The E4B PLE table (embed_tokens_per_layer, ~5GB bf16 -> ~10GB
                # f32; whole-tensor Q8 encode peaks >20GB) needs no per-element
                # transform, so stream it block-at-a-time from the safetensors
                # slice. Skips tensors needing a layout transform (llama q/k rope
                # permute) or a forced-F32 encode.
                _slice = f.get_slice(hf_name)
                _shape = tuple(int(d) for d in _slice.get_shape())
                _numel = int(np.prod(_shape)) if _shape else 0
                _is_qk = (canon.endswith(".attn_q.weight")
                          or canon.endswith(".attn_k.weight"))
                if (_numel >= STREAM_Q8_THRESHOLD and len(_shape) == 2
                        and os.getenv("KNOT_FORCE_F32") != "1"
                        and not (arch == "llama" and _is_qk)):
                    writer.add_q8_streamed(canon, _slice, _shape)
                    print(f"    [stream-q8] {canon} {_shape} "
                          f"({_numel / 1e9:.2f}B elems)")
                    n_written += 1
                    continue

                arr = _to_f32(f.get_tensor(hf_name))
                # ── HF-llama RoPE layout fix ──────────────────────────────────
                # HF LlamaForCausalLM stores q_proj/k_proj in the "NeoX"
                # (rotate_half) RoPE layout: rotation pairs are (x[i], x[i+d/2]).
                # The native runtime's arch=="llama" path applies the *interleaved*
                # rotation (pairs (x[2i], x[2i+1])) — the llama.cpp/GGUF convention.
                # Feeding HF-layout weights to the interleaved rope scrambles
                # positional info: weak models (TinyLlama-1.1B) regress to
                # near-position-invariant output (correct token demoted ~1 logit).
                # llama.cpp fixes this by PERMUTING q/k at HF->GGUF conversion;
                # do the same here so the knot is internally consistent with the
                # runtime's interleaved rope. Only for arch=="llama"; qwen2/gemma/
                # etc. use rope_neox in the runtime and keep the HF layout as-is.
                _is_q = canon.endswith(".attn_q.weight")
                _is_k = canon.endswith(".attn_k.weight")
                if arch == "llama" and (_is_q or _is_k):
                    n_h = (knot_cfg["num_heads"] if _is_q
                           else knot_cfg.get("num_kv_heads", knot_cfg["num_heads"]))
                    hd = arr.shape[0] // n_h
                    arr = (
                        arr.reshape(n_h, 2, hd // 2, arr.shape[1])
                        .swapaxes(1, 2)
                        .reshape(arr.shape)
                    )
                # KNOT_F32_HEADS=1: keep the output projection (lm_head) and the
                # input embedding table in F32 instead of the default Q8 (the
                # "keep lm_head F32" admitted-fix pattern). Q8 on the final head
                # of a small (1.1B) llama compresses the logit spread enough to
                # demote the correct argmax by ~1 logit; F32 preserves the margin.
                if os.getenv("KNOT_F32_HEADS") == "1" and canon in (
                    "output.weight", "token_embd.weight"
                ):
                    writer.add_f32(canon, arr)
                else:
                    writer.add_auto(canon, arr)
                n_written += 1
                # Capture the embed table so we can emit a tied output.weight.
                if canon == "token_embd.weight" and tie_embeddings:
                    embed_arr_for_tie = arr
                if n_written % 50 == 0:
                    print(f"[knot]   {n_written} tensors written ...", file=sys.stderr)
        _maybe_delete_shard_after_encode(local_dir, shard_path)

    # Emit tied lm_head (output.weight) when the model ties embeddings and the
    # state_dict carried no explicit lm_head. NativeLlama resolves output.weight
    # for the final projection; without it the head reads zeros.
    if tie_embeddings and not saw_lm_head and embed_arr_for_tie is not None:
        writer.add_auto("output.weight", embed_arr_for_tie)
        n_written += 1
        print("[knot] tie_word_embeddings: wrote output.weight = token_embd.weight",
              file=sys.stderr)

    print(f"[knot] mapped {n_written} tensors, skipped {n_skipped}", file=sys.stderr)
    writer.write(output_path)
    if arch == "flux":
        _validate_written_flux_knot(output_path)


# ─────────────────────────────────────────────────────────────────────────────
# CLI
# ─────────────────────────────────────────────────────────────────────────────

def main() -> None:
    ap = argparse.ArgumentParser(
        description="Encode a standard HF transformer to KNOT format for fat-station.")
    ap.add_argument("--model", required=True,
                    help="HuggingFace model ID or local path")
    ap.add_argument("--output", required=True, type=Path,
                    help="Output .knot file path")
    ap.add_argument("--hf-token", default=os.getenv("HF_TOKEN"),
                    help="HuggingFace access token (default: $HF_TOKEN)")
    ap.add_argument("--max-layers", type=int, default=None,
                    help="Encode only the first N transformer blocks (fast iteration)")
    ap.add_argument("--capture-all", action="store_true",
                    help="Keep tensors with no canonical mapping (verbatim, "
                         "dots->underscores) instead of skipping them — e.g. the "
                         "E4B vision/audio towers, for a multimodal-ready knot.")
    ap.add_argument("--revision", default="main",
                    help="HuggingFace revision/branch (default: main)")
    args = ap.parse_args()

    encode(
        args.model, args.output,
        hf_token=args.hf_token,
        max_layers=args.max_layers,
        revision=args.revision,
        capture_all=args.capture_all,
    )


if __name__ == "__main__":
    main()
